import Logger from 'bunyan';
import { ApiConfig, RestClient } from '@ministryofjustice/hmpps-rest-client';
import { Request } from 'express';
import { createClient } from 'redis';

interface AuthenticatedRequest extends Request {
    verified?: boolean;
    user: {
        username: string;
        token: string;
        authSource: string;
    };
}

interface VerifyConfig extends ApiConfig {
    enabled: boolean;
}

/**
 * A client for verifying tokens using the HMPPS Token Verification API.
 * @class
 * @extends RestClient
 *
 * @example
 * import VerificationClient from './VerificationClient'
 *
 * const verifyClient = new VerificationClient(
 *   {
 *     enabled: true,
 *     ...ApiConfig
 *   },
 *   console
 * )
 *
 * const isValid = await verifyClient.verifyToken({ user: { username: 'some-user', token: 'abc123' } })
 */
declare class VerificationClient extends RestClient {
    protected readonly config: VerifyConfig;
    protected readonly logger: Logger | Console;
    /**
     * Creates an instance of VerificationClient.
     * @param {VerifyConfig} config - The VerifyConfig settings for the token verification client.
     * @param {Logger|Console} logger - The logging mechanism.
     */
    constructor(config: VerifyConfig, logger: Logger | Console);
    /**
     * Verifies a token for a given AuthenticatedRequest.
     * @param {AuthenticatedRequest} request - The request object containing user credentials and verification status.
     * @returns {Promise<boolean>} - A promise that resolves to true if valid or if verification is disabled; otherwise false.
     */
    verifyToken(request: AuthenticatedRequest): Promise<boolean>;
}

interface TokenStore {
    setToken(key: string, token: string, durationSeconds: number): Promise<void>;
    getToken(key: string): Promise<string | null>;
}

interface AuthConfig extends ApiConfig {
    systemClientId: string;
    systemClientSecret: string;
}

/**
 * A client for authenticating with the HMPPS Auth API, retrieving tokens for system usage or impersonation.
 * @class
 * @extends RestClient
 *
 * @example
 * import AuthenticationClient from './AuthenticationClient'
 *
 * const authClient = new AuthenticationClient(
 *   {
 *     systemClientId: 'client-id',
 *     systemClientSecret: 'client-secret',
 *     ...ApiConfig
 *   },
 *   console
 * )
 *
 * const token = await authClient.getToken('some-user')
 */
declare class AuthenticationClient extends RestClient {
    protected readonly config: AuthConfig;
    protected readonly logger: Logger | Console;
    private readonly tokenStore;
    /**
     * Creates an instance of AuthenticationClient.
     * @param {AuthConfig} config - The AuthConfig settings for the client.
     * @param {Logger|Console} logger - The logging mechanism.
     * @param {TokenStore} [tokenStore=new InMemoryTokenStore()] - Optional token store to cache tokens.
     */
    constructor(config: AuthConfig, logger: Logger | Console, tokenStore?: TokenStore);
    /**
     * Retrieves a token from the token store or fetches a new one from the HMPPS Auth API.
     * @param {string} [username] - An optional username to impersonate; if omitted, a system (anonymous) token is fetched.
     * @returns {Promise<string>} - A promise that resolves with the retrieved or newly fetched token.
     */
    getToken(username?: string): Promise<string>;
}

type RedisClient = ReturnType<typeof createClient>;

/**
 * A token store implementation using Redis as the backend.
 * The default Redis key prefix is `systemToken`. This can be customised using the optional constructor arg.

 * @class
 * @implements {TokenStore}
 *
 * @example using the default prefix
 * import RedisTokenStore from './tokenStores/RedisTokenStore'
 * import { createClient } from 'redis'
 *
 * const redisClient = createClient() // Use the redis library
 * const tokenStore = new RedisTokenStore(redisClient)
 * await tokenStore.setToken('some-key', 'abc123', 3600)
 * const token = await tokenStore.getToken('some-key')
 *
 * // Redis will have stored the token with the key `systemToken:some-key`
 *
 *
 * @example using a custom prefix
 * import RedisTokenStore from './tokenStores/RedisTokenStore'
 * import { createClient } from 'redis'
 *
 * const redisClient = createClient() // Use the redis library
 * const tokenStore = new RedisTokenStore(redisClient, 'otherTokens')
 * await tokenStore.setToken('some-key', 'abc123', 3600)
 * const token = await tokenStore.getToken('some-key')
 *
 * // Redis will have stored the token with the key `otherTokens:some-key`
 */
declare class RedisTokenStore implements TokenStore {
    private readonly client;
    private readonly prefix;
    /**
     * Creates an instance of RedisTokenStore.
     * @param {RedisClient} client - A Redis client instance.
     * @param {string} prefix - An optional prefix that will be used for all keys set and retrieved via this token store.
     *                          Default is `systemToken`
     */
    constructor(client: RedisClient, prefix?: string);
    /**
     * Ensures the Redis client is connected.
     * @private
     * @returns {Promise<void>}
     */
    private ensureConnected;
    /**
     * Stores a token in Redis with a specified expiration.
     * @param {string} key - The key under which to store the token.
     * @param {string} token - The token string.
     * @param {number} durationSeconds - The number of seconds the token remains valid.
     * @returns {Promise<void>}
     */
    setToken(key: string, token: string, durationSeconds: number): Promise<void>;
    /**
     * Retrieves a token from Redis by key.
     * @param {string} key - The key associated with the token.
     * @returns {Promise<string | null>} - A promise that resolves with the token or null if not found or expired.
     */
    getToken(key: string): Promise<string | null>;
}

/**
 * An in-memory token store implementation for development or testing.
 * @class
 * @implements {TokenStore}
 *
 * @example
 * import InMemoryTokenStore from './tokenStores/InMemoryTokenStore'
 *
 * const tokenStore = new InMemoryTokenStore()
 * await tokenStore.setToken('some-key', 'abc123', 3600)
 * const token = await tokenStore.getToken('some-key')
 */
declare class InMemoryTokenStore implements TokenStore {
    private readonly map;
    /**
     * Stores a token in memory with a specified expiration.
     * @param {string} key - The key under which to store the token.
     * @param {string} token - The token string.
     * @param {number} durationSeconds - The number of seconds the token remains valid.
     * @returns {Promise<void>}
     */
    setToken(key: string, token: string, durationSeconds: number): Promise<void>;
    /**
     * Retrieves a token from memory by key.
     * @param {string} key - The key associated with the token.
     * @returns {Promise<string | null>} - A promise that resolves with the token or null if not found or expired.
     */
    getToken(key: string): Promise<string | null>;
}

export { AuthenticationClient, InMemoryTokenStore, RedisTokenStore, VerificationClient };
export type { AuthConfig, AuthenticatedRequest, TokenStore, VerifyConfig };
